(self.webpackChunk=self.webpackChunk||[]).push([[805],{7499:(s,n,e)=>{"use strict";e.r(n),e.d(n,{data:()=>a});const a={key:"v-6eed7416",path:"/docker/docker-install.html",title:"安装Docker",lang:"en-US",frontmatter:{title:"安装Docker"},excerpt:"",headers:[{level:2,title:"Docker安装（centos）",slug:"docker安装-centos",children:[{level:3,title:"1.删除已安装的Docker",slug:"_1-删除已安装的docker",children:[]},{level:3,title:"2.配置阿里云Docker Yum源",slug:"_2-配置阿里云docker-yum源",children:[]},{level:3,title:"3.安装指定版本",slug:"_3-安装指定版本",children:[]},{level:3,title:"4.启用阿里云Docker镜像加速",slug:"_4-启用阿里云docker镜像加速",children:[]},{level:3,title:"5.启动Docker服务",slug:"_5-启动docker服务",children:[]}]},{level:2,title:"docker安装(debian)",slug:"docker安装-debian",children:[{level:3,title:"1.卸载旧版本",slug:"_1-卸载旧版本",children:[]},{level:3,title:"2.使用 Docker 仓库进行安装",slug:"_2-使用-docker-仓库进行安装",children:[]},{level:3,title:"3.安装 Docker Engine-Community",slug:"_3-安装-docker-engine-community",children:[]}]},{level:2,title:"一键脚本安装(通用)",slug:"一键脚本安装-通用",children:[]},{level:2,title:"Docker 用户组设置",slug:"docker-用户组设置",children:[{level:3,title:"1.创建docker用户组（正常来说docker安装后会自动有docker用户组）",slug:"_1-创建docker用户组-正常来说docker安装后会自动有docker用户组",children:[]},{level:3,title:"2.两步选一步",slug:"_2-两步选一步",children:[]},{level:3,title:"3.重启docker",slug:"_3-重启docker",children:[]}]},{level:2,title:"Docker-compose安装",slug:"docker-compose安装",children:[{level:3,title:"源码安装 *",slug:"源码安装",children:[]},{level:3,title:"pip安装",slug:"pip安装",children:[]}]}],filePathRelative:"docker/docker-install.md",git:{updatedTime:1626154667e3,contributors:[]}}},5766:(s,n,e)=>{"use strict";e.r(n),e.d(n,{default:()=>l});const a=(0,e(6252).uE)('<h2 id="docker安装-centos" tabindex="-1"><a class="header-anchor" href="#docker安装-centos" aria-hidden="true">#</a> Docker安装（centos）</h2><h3 id="_1-删除已安装的docker" tabindex="-1"><a class="header-anchor" href="#_1-删除已安装的docker" aria-hidden="true">#</a> 1.删除已安装的Docker</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>    <span class="token function">sudo</span> yum remove docker <span class="token punctuation">\\</span>\n                     docker-client <span class="token punctuation">\\</span>\n                     docker-client-latest <span class="token punctuation">\\</span>\n                     docker-common <span class="token punctuation">\\</span>\n                     docker-latest <span class="token punctuation">\\</span>\n                     docker-latest-logrotate <span class="token punctuation">\\</span>\n                     docker-logrotate <span class="token punctuation">\\</span>\n                     docker-selinux <span class="token punctuation">\\</span>\n                     docker-engine-selinux <span class="token punctuation">\\</span>\n                     docker-engine\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="_2-配置阿里云docker-yum源" tabindex="-1"><a class="header-anchor" href="#_2-配置阿里云docker-yum源" aria-hidden="true">#</a> 2.配置阿里云Docker Yum源</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code> <span class="token function">sudo</span> yum <span class="token function">install</span> -y yum-utils device-mapper-persistent-data lvm2\n <span class="token function">sudo</span> yum-config-manager --add-repo http://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_3-安装指定版本" tabindex="-1"><a class="header-anchor" href="#_3-安装指定版本" aria-hidden="true">#</a> 3.安装指定版本</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>     yum list docker-ce --showduplicates\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><ul><li>3.1、安装较旧版本</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>//注意：需要指定完整的rpm包的包名，并且加上--setopt<span class="token operator">=</span>obsoletes<span class="token operator">=</span><span class="token number">0</span> 参数：\n    yum <span class="token function">install</span> -y --setopt<span class="token operator">=</span>obsoletes<span class="token operator">=</span><span class="token number">0</span> <span class="token punctuation">\\</span>\n   docker-ce-17.03.2.ce-1.el7.centos.x86_64 <span class="token punctuation">\\</span>\n   docker-ce-selinux-17.03.2.ce-1.el7.centos.noarch\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>3.2、安装Docker最新版本</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">sudo</span> yum <span class="token function">install</span> docker-ce\ncentos8 遇到containerd.io版本问题 http://mirrors.aliyun.com/docker-ce/linux/centos/7/x86_64/stable/Packages/ 手动下载安装\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_4-启用阿里云docker镜像加速" tabindex="-1"><a class="header-anchor" href="#_4-启用阿里云docker镜像加速" aria-hidden="true">#</a> 4.启用阿里云Docker镜像加速</h3><p>https://cr.console.aliyun.com 自己申请账号，下面是我自己的</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">mkdir</span> -p /etc/docker\n<span class="token function">sudo</span> <span class="token function">tee</span> /etc/docker/daemon.json <span class="token operator">&lt;&lt;-</span><span class="token string">&#39;EOF&#39;\n{\n  &quot;registry-mirrors&quot;: [&quot;https://a0cmmvhl.mirror.aliyuncs.com&quot;]\n}\nEOF</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="_5-启动docker服务" tabindex="-1"><a class="header-anchor" href="#_5-启动docker服务" aria-hidden="true">#</a> 5.启动Docker服务</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>systemctl <span class="token builtin class-name">enable</span> docker\nsystemctl start docker\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="docker安装-debian" tabindex="-1"><a class="header-anchor" href="#docker安装-debian" aria-hidden="true">#</a> docker安装(debian)</h2><h3 id="_1-卸载旧版本" tabindex="-1"><a class="header-anchor" href="#_1-卸载旧版本" aria-hidden="true">#</a> 1.卸载旧版本</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>sudo apt-get remove docker docker-engine docker.io containerd runc\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="_2-使用-docker-仓库进行安装" tabindex="-1"><a class="header-anchor" href="#_2-使用-docker-仓库进行安装" aria-hidden="true">#</a> 2.使用 Docker 仓库进行安装</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>#设置仓库\n#更新 apt 包索引\nsudo apt-get update\n#安装 apt 依赖包，用于通过 HTTPS 来获取仓库\nsudo apt-get install \\\n    apt-transport-https \\\n    ca-certificates \\\n    curl \\\n    gnupg2 \\\n    software-properties-common\n#添加 Docker 的官方 GPG 密钥\ncurl -fsSL https://download.docker.com/linux/debian/gpg | sudo apt-key add -\n# 9DC8 5822 9FC7 DD38 854A E2D8 8D81 803C 0EBF CD88 通过搜索指纹的后8个字符，验证您现在是否拥有带有指纹的密钥\nsudo apt-key fingerprint 0EBFCD88\n#使用以下指令设置稳定版仓库\nsudo add-apt-repository \\\n   &quot;deb [arch=amd64] https://download.docker.com/linux/debian \\\n  $(lsb_release -cs) \\\n  stable&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h3 id="_3-安装-docker-engine-community" tabindex="-1"><a class="header-anchor" href="#_3-安装-docker-engine-community" aria-hidden="true">#</a> 3.安装 Docker Engine-Community</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>#更新 apt 包索引\nsudo apt-get update\n#安装最新版本的 Docker Engine-Community 和 containerd ，或者转到下一步安装特定版本：\nsudo apt-get install docker-ce docker-ce-cli containerd.io\n#要安装特定版本的 Docker Engine-Community，请在仓库中列出可用版本，然后选择一种安装。列出您的仓库中可用的版本：\napt-cache madison docker-ce\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="一键脚本安装-通用" tabindex="-1"><a class="header-anchor" href="#一键脚本安装-通用" aria-hidden="true">#</a> 一键脚本安装(通用)</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">curl</span> -fsSL https://get.docker.com <span class="token operator">|</span> <span class="token function">bash</span> -s docker --mirror Aliyun\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>或者使用<code>Daocloud</code>的</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">curl</span> -sSL https://get.daocloud.io/docker <span class="token operator">|</span> <span class="token function">sh</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="docker-用户组设置" tabindex="-1"><a class="header-anchor" href="#docker-用户组设置" aria-hidden="true">#</a> Docker 用户组设置</h2><h3 id="_1-创建docker用户组-正常来说docker安装后会自动有docker用户组" tabindex="-1"><a class="header-anchor" href="#_1-创建docker用户组-正常来说docker安装后会自动有docker用户组" aria-hidden="true">#</a> 1.创建docker用户组（正常来说docker安装后会自动有docker用户组）</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">groupadd</span> docker\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="_2-两步选一步" tabindex="-1"><a class="header-anchor" href="#_2-两步选一步" aria-hidden="true">#</a> 2.两步选一步</h3><ul><li>2.1将当前用户添加进组</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">sudo</span> gpasswd -a <span class="token variable">${<span class="token environment constant">USER</span>}</span> docker\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><ul><li>2.2添加指定用户进组</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">usermod</span>  -aG docker <span class="token variable">${用户名}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="_3-重启docker" tabindex="-1"><a class="header-anchor" href="#_3-重启docker" aria-hidden="true">#</a> 3.重启docker</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">sudo</span> systemctl restart docker\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="docker-compose安装" tabindex="-1"><a class="header-anchor" href="#docker-compose安装" aria-hidden="true">#</a> Docker-compose安装</h2><h3 id="源码安装" tabindex="-1"><a class="header-anchor" href="#源码安装" aria-hidden="true">#</a> 源码安装 <sup><span style="color:#F00;font-size:4;">*</span></sup></h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment">#临时写tag为系统变量 （实测centos8不支持$()，仅支持``）</span>\n<span class="token builtin class-name">export</span> <span class="token assign-left variable">tag</span><span class="token operator">=</span><span class="token variable"><span class="token variable">`</span><span class="token function">wget</span> -qO- -t1 -T2 <span class="token string">&quot;https://api.github.com/repos/docker/compose/releases/latest&quot;</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token string">&quot;tag_name&quot;</span> <span class="token operator">|</span> <span class="token function">head</span> -n <span class="token number">1</span> <span class="token operator">|</span> <span class="token function">awk</span> -F <span class="token string">&quot;:&quot;</span> <span class="token string">&#39;{print $2}&#39;</span> <span class="token operator">|</span> <span class="token function">sed</span> <span class="token string">&#39;s/\\&quot;//g;s/,//g;s/ //g&#39;</span><span class="token variable">`</span></span>\n\n<span class="token function">curl</span> -L https://github.com/docker/compose/releases/download/<span class="token variable">${tag}</span>/docker-compose-<span class="token variable"><span class="token variable">`</span><span class="token function">uname</span> -s<span class="token variable">`</span></span>-<span class="token variable"><span class="token variable">`</span><span class="token function">uname</span> -m<span class="token variable">`</span></span> <span class="token operator">&gt;</span> /usr/local/bin/docker-compose\n\n<span class="token function">chmod</span> +x /usr/local/bin/docker-compose\n\n<span class="token comment">#验证</span>\ndocker-compose --version\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="pip安装" tabindex="-1"><a class="header-anchor" href="#pip安装" aria-hidden="true">#</a> pip安装</h3><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment">###安装python-pip</span>\nyum -y <span class="token function">install</span> epel-release\nyum -y <span class="token function">install</span> python-pip   <span class="token comment">#若后续安装docker-compose失败，使用 yum -y install python3-pip</span>\npip <span class="token function">install</span> --upgrade pip\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>安装docker-compose</li></ul><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment">#若安装的是python-pip3,则此处命令为pip3 install docker-compose</span>\npip <span class="token function">install</span> docker-compose \n\n<span class="token comment">#验证</span>\ndocker-compose version\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div>',44),l={render:function(s,n){return a}}}}]);